// n8n Code 節點 - GET /webhook/result
// 修正：處理 MySQL Stored Procedure 回傳的巢狀陣列

const items = $input.all();

// MySQL CALL 回傳格式是 [[row], {metadata}]
// 第一個元素是陣列，裡面才是真正的資料
let row = null;

if (items && items.length > 0) {
  const firstItem = items[0].json;

  // 如果是陣列（Stored Procedure 的結果）
  if (Array.isArray(firstItem)) {
    row = firstItem[0];
  } else {
    row = firstItem;
  }
}

// 如果沒有資料
if (!row || !row.session_id) {
  return [{
    json: {
      status: "pending",
      message: "分析中，請稍候..."
    }
  }];
}

// ===== 輔助函式 =====

function parseJsonField(field) {
  if (!field) return null;
  if (typeof field === 'string') {
    try {
      return JSON.parse(field);
    } catch (e) {
      return null;
    }
  }
  // 已經是物件或陣列，直接回傳
  return field;
}

const ISSUE_LABELS = {
  'acne': '痘痘',
  'comedone': '粉刺',
  'darkCircle': '黑眼圈',
  'dark_circle': '黑眼圈',
  'spot': '斑點',
  'wrinkle': '細紋'
};

function translateIssueName(englishName) {
  if (!englishName) return '';
  return ISSUE_LABELS[englishName] || englishName;
}

// 處理 ingredients（可能是字串陣列或物件陣列）
function normalizeIngredients(ingredients) {
  const parsed = parseJsonField(ingredients);
  if (!parsed) return [];

  // 如果是字串陣列 ["菸鹼醯胺", "甘草萃取"]
  if (Array.isArray(parsed) && typeof parsed[0] === 'string') {
    return parsed.map(name => ({ name: name, description: '' }));
  }

  // 如果已經是物件陣列 [{name: "xxx"}]
  return parsed;
}

// ===== 組裝結果 =====

const result = {
  status: "completed",
  data: {
    sectionA: {
      photoUrl: row.original_photo_url || '',
      score: Number(row.a_score) || 0,
      evaluation: row.a_complexion_text || '',
      massages: parseJsonField(row.a_massage_action) || []
    },
    sectionB: {
      maskedPhotoUrl: row.analyzed_photo_url || row.original_photo_url || '',
      scores: {
        acne: Number(row.acne_score) || 0,
        comedone: Number(row.comedone_score) || 0,
        darkCircle: Number(row.dark_circle_score) || 0,
        spot: Number(row.spot_score) || 0,
        wrinkle: Number(row.wrinkle_score) || 0
      },
      topIssues: [
        {
          id: row.top_1_issues || '',
          name: translateIssueName(row.top_1_issues),
          description: row.llm_1_text || ''
        },
        {
          id: row.top_2_issues || '',
          name: translateIssueName(row.top_2_issues),
          description: row.llm_2_text || ''
        }
      ].filter(issue => issue.name)
    },
    sectionC: {
      suggestions: parseJsonField(row.dietary_advice) || []
    },
    sectionD: {
      products: parseJsonField(row.matched_ingredients) || []
    },
    questionnaire: {
      answer3_tag: row.answer3_tag || ''
    }
  }
};

return [{
  json: result
}];

